1	interface Item {
2	  type: string;
3	}
4	
5	interface Policy {
6	  items: Item[];
7	  customer: { yearsWithMHPCO: number };
8	  isFollowUp: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25 };
14	const DEFAULT_BASE_PREMIUM = 60;
15	
16	const BLOCK_SIZE = 3;
17	const BLOCK_PREMIUM = 60;
18	
19	function countByType(items: Item[]): Record<string, number> {
20	  const counts: Record<string, number> = {};
21	  for (const item of items) {
22	    counts[item.type] = (counts[item.type] ?? 0) + 1;
23	  }
24	  return counts;
25	}
26	
27	export function quote(policy: Policy) {
28	  let basePremium = 0;
29	
30	  const counts = countByType(policy.items);
31	
32	  for (const [type, count] of Object.entries(counts)) {
33	    if (count === BLOCK_SIZE) {
34	      basePremium += BLOCK_PREMIUM;
35	    } else {
36	      basePremium += count * (BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM);
37	    }
38	  }
39	
40	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
41	  const premium = Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
42	  return { premium };
43	}
44	
45	export function claim() {
46	  return undefined;
47	}
